#!/usr/bin/env python3
"""gguf_meta.py — header-only GGUF inspector.

Parses the GGUF KV-metadata + tensor-info sections WITHOUT touching tensor
data, so it works on partially-downloaded `.incomplete` blobs (the header is
at the file start). Prints architecture, all scalar KV fields, and a sample of
tensor names/types (first-layer tensors + any MoE/expert/vision tensors).

Usage: python gguf_meta.py FILE.gguf [--tensors]
"""
import struct, sys

GGUF_MAGIC = 0x46554747  # 'GGUF' little-endian

# GGUF metadata value types
(T_U8, T_I8, T_U16, T_I16, T_U32, T_I32, T_F32, T_BOOL, T_STR, T_ARR,
 T_U64, T_I64, T_F64) = range(13)

_FIXED = {T_U8: ("<B", 1), T_I8: ("<b", 1), T_U16: ("<H", 2), T_I16: ("<h", 2),
          T_U32: ("<I", 4), T_I32: ("<i", 4), T_F32: ("<f", 4), T_BOOL: ("<?", 1),
          T_U64: ("<Q", 8), T_I64: ("<q", 8), T_F64: ("<d", 8)}

GGML_TYPE = {0: "F32", 1: "F16", 2: "Q4_0", 3: "Q4_1", 6: "Q5_0", 7: "Q5_1",
             8: "Q8_0", 9: "Q8_1", 10: "Q2_K", 11: "Q3_K", 12: "Q4_K",
             13: "Q5_K", 14: "Q6_K", 15: "Q8_K", 16: "IQ2_XXS", 17: "IQ2_XS",
             18: "IQ3_XXS", 19: "IQ1_S", 20: "IQ4_NL", 21: "IQ3_S", 22: "IQ2_S",
             23: "IQ4_XS", 24: "I8", 25: "I16", 26: "I32", 27: "I64", 28: "F64",
             29: "IQ1_M", 30: "BF16"}


class Reader:
    def __init__(self, f):
        self.f = f
    def read(self, n):
        b = self.f.read(n)
        if len(b) < n:
            raise EOFError("truncated header")
        return b
    def u32(self): return struct.unpack("<I", self.read(4))[0]
    def u64(self): return struct.unpack("<Q", self.read(8))[0]
    def scalar(self, t):
        fmt, sz = _FIXED[t]
        return struct.unpack(fmt, self.read(sz))[0]
    def gstr(self):
        n = self.u64()
        return self.read(n).decode("utf-8", "replace")
    def value(self, t):
        if t in _FIXED:
            return self.scalar(t)
        if t == T_STR:
            return self.gstr()
        if t == T_ARR:
            sub = self.u32()
            n = self.u64()
            if sub == T_STR:
                # skip/collect strings; keep only count for big arrays
                if n > 64:
                    for _ in range(n):
                        self.read(self.u64())
                    return f"<{n} strings>"
                return [self.gstr() for _ in range(n)]
            if sub in _FIXED:
                fmt, sz = _FIXED[sub]
                if n > 64:
                    self.read(sz * n)
                    return f"<{n} x type{sub}>"
                return [struct.unpack(fmt, self.read(sz))[0] for _ in range(n)]
            raise ValueError(f"nested array subtype {sub}")
        raise ValueError(f"unknown value type {t}")


def parse(path):
    with open(path, "rb") as fh:
        r = Reader(fh)
        magic = r.u32()
        assert magic == GGUF_MAGIC, f"bad magic {magic:#x}"
        ver = r.u32()
        n_tensors = r.u64()
        n_kv = r.u64()
        kv = {}
        for _ in range(n_kv):
            key = r.gstr()
            vt = r.u32()
            kv[key] = r.value(vt)
        tensors = []  # (name, dims, type_str)
        try:
            for _ in range(n_tensors):
                name = r.gstr()
                nd = r.u32()
                dims = [r.u64() for _ in range(nd)]
                tt = r.u32()
                off = r.u64()
                tensors.append((name, dims, GGML_TYPE.get(tt, f"type{tt}")))
        except EOFError:
            pass  # tensor-info section may be truncated on partial files
        return ver, n_tensors, kv, tensors


def main():
    path = sys.argv[1]
    show_tensors = "--tensors" in sys.argv
    ver, n_tensors, kv, tensors = parse(path)
    arch = kv.get("general.architecture")
    print(f"=== {path}")
    print(f"version={ver} n_tensors={n_tensors} (tensor-infos parsed: {len(tensors)})")
    print(f"arch={arch!r} name={kv.get('general.name')!r}")
    print("--- scalar KV (filtered) ---")
    for k in sorted(kv):
        v = kv[k]
        if isinstance(v, str) and v.startswith("<"):
            continue  # big arrays
        if k.startswith("tokenizer."):
            continue
        print(f"  {k} = {v}")
    if show_tensors and tensors:
        print("--- tensor sample (layer 0 + MoE/vision/embed/output) ---")
        seen_types = {}
        for name, dims, tt in tensors:
            seen_types[tt] = seen_types.get(tt, 0) + 1
        for name, dims, tt in tensors:
            keep = (
                ".0." in name or name.startswith("blk.0.")
                or any(s in name for s in ["exps", "expert", "ffn_gate_inp", "gate_inp",
                                            "token_embd", "output", "_norm"])
                or "blk." not in name
            )
            if keep:
                print(f"  {name}  dims={dims}  {tt}")
        print(f"--- ggml type histogram: {seen_types}")


if __name__ == "__main__":
    main()
